import time
from enum import Enum
from dataclasses import dataclass, field
from typing import Callable, TypeVar, Optional

T = TypeVar("T")

class CircuitState(str, Enum):
    CLOSED = "closed"       # normal operation
    OPEN = "open"           # failing — reject calls immediately
    HALF_OPEN = "half_open" # testing if service recovered

@dataclass
class CircuitBreaker:
    failure_threshold: int = 5
    recovery_timeout: float = 30.0   # seconds before trying again
    _failures: int = field(default=0, init=False, repr=False)
    _state: CircuitState = field(default=CircuitState.CLOSED, init=False, repr=False)
    _last_failure_time: Optional[float] = field(default=None, init=False, repr=False)

    def call(self, fn: Callable[[], T], fallback: Callable[[], T]) -> T:
        if self._state == CircuitState.OPEN:
            if time.monotonic() - self._last_failure_time >= self.recovery_timeout:
                self._state = CircuitState.HALF_OPEN
            else:
                return fallback()

        try:
            result = fn()
            if self._state == CircuitState.HALF_OPEN:
                self._reset()
            return result
        except Exception as exc:
            self._record_failure()
            if self._state == CircuitState.OPEN:
                return fallback()
            raise

    def _record_failure(self) -> None:
        self._failures += 1
        self._last_failure_time = time.monotonic()
        if self._failures >= self.failure_threshold:
            self._state = CircuitState.OPEN

    def _reset(self) -> None:
        self._failures = 0
        self._state = CircuitState.CLOSED
        self._last_failure_time = None

# Usage — wrap every external call
llm_breaker = CircuitBreaker(failure_threshold=5, recovery_timeout=30.0)

def call_llm(prompt: str) -> str:
    return llm_breaker.call(
        fn=lambda: openai_client.chat(prompt),
        fallback=lambda: "I'm temporarily unavailable. Please try again shortly.",
    )
